CHROME_HEADLESS = os.getenv("CHROME_HEADLESS", "1") != "0"

DEFAULT_VIEWPORT_W = int(os.getenv("DEFAULT_VIEWPORT_W", "1200"))
DEFAULT_VIEWPORT_H = int(os.getenv("DEFAULT_VIEWPORT_H", "630"))
DEFAULT_TIMEOUT_MS = int(os.getenv("DEFAULT_TIMEOUT_MS", "20000"))
