THUMB_W = int(os.getenv("THUMB_W", "600"))
THUMB_H = int(os.getenv("THUMB_H", "315"))
THUMB_FORMAT = os.getenv("THUMB_FORMAT", "jpeg").lower()  # jpeg/png/webp
THUMB_QUALITY = int(os.getenv("THUMB_QUALITY", "82"))

MAX_URL_LEN = int(os.getenv("MAX_URL_LEN", "2048"))
MAX_CONCURRENT = int(os.getenv("MAX_CONCURRENT", "2"))

ALLOW_PRIVATE_NETS = os.getenv("ALLOW_PRIVATE_NETS", "0") == "1"
ALLOWED_SCHEMES = set((os.getenv("ALLOWED_SCHEMES", "http,https")).split(","))

LOG_LEVEL = os.getenv("LOG_LEVEL", "INFO").upper()

