_s3 = boto3.client(
    "s3",
    region_name=AWS_REGION,
    endpoint_url=S3_ENDPOINT_URL,
    config=Config(retries={"max_attempts": 5, "mode": "standard"}),
)

_sema = threading.Semaphore(MAX_CONCURRENT)


def _now_iso():
    return datetime.now(timezone.utc).isoformat()


def _is_ip_private_or_local(host: str) -> bool:
    import ipaddress
    try:
        ip = ipaddress.ip_address(host)
        return (
            ip.is_private
            or ip.is_loopback
            or ip.is_link_local
            or ip.is_multicast
            or ip.is_reserved
            or ip.is_unspecified
        )
    except ValueError:
        return False


def _dns_resolves_to_private(host: str) -> bool:
    import socket
    import ipaddress
    try:
        infos = socket.getaddrinfo(host, None)
        for info in infos:
            addr = info[4][0]
            try:
                ip = ipaddress.ip_address(addr)
                if (
                    ip.is_private
                    or ip.is_loopback
                    or ip.is_link_local
                    or ip.is_multicast
                    or ip.is_reserved
                    or ip.is_unspecified
                ):
                    return True
            except ValueError:
                continue
        return False
    except Exception:
        return True


def validate_url(url: str) -> (bool, str):
    if not url or not isinstance(url, str):
        return False, "missing_url"
    url = url.strip()
    if len(url) > MAX_URL_LEN:
        return False, "url_too_long"
    try:
        p = urlparse(url)
    except Exception:
        return False, "invalid_url"
    if p.scheme not in ALLOWED_SCHEMES:
        return False, "invalid_scheme"
    if not p.netloc:
        return False, "missing_host"
    host = p.hostname or ""
    if not host:
        return False, "missing_host"
    if not ALLOW_PRIVATE_NETS:
        if _is_ip_private_or_local(host):
            return False, "private_ip_blocked"
        if _dns_resolves_to_private(host):
            return False, "private_dns_blocked"
    return True, ""


def _stable_key(url: str, w: int, h: int, tw: int, th: int, fmt: str) -> str:
    hsh = hashlib.sha256(f"{url}|{w}x{h}|{tw}x{th}|{fmt}".encode("utf-8")).hexdigest()
    return f"{S3_PREFIX}/{hsh[:2]}/{hsh[2:4]}/{hsh}.{fmt}"


def _s3_head(key: str):
    try:
        return _s3.head_object(Bucket=S3_BUCKET, Key=key)
    except ClientError as e:
        code = e.response.get("Error", {}).get("Code", "")
        if code in ("404", "NoSuchKey", "NotFound"):
            return None
        raise


def _s3_put_bytes(key: str, data: bytes, content_type: str):
    extra = {
        "Bucket": S3_BUCKET,
        "Key": key,
        "Body": data,
        "ContentType": content_type,
        "CacheControl": S3_CACHE_CONTROL,
    }
    if S3_ACL:
        extra["ACL"] = S3_ACL
    _s3.put_object(**extra)


def _s3_presigned_get(key: str, expires: int = 3600) -> str:
    return _s3.generate_presigned_url(
        "get_object",
        Params={"Bucket": S3_BUCKET, "Key": key},
        ExpiresIn=expires,
    )


def _content_type_for(fmt: str) -> str:
    if fmt == "png":
        return "image/png"
    if fmt == "webp":
        return "image/webp"
    return "image/jpeg"


def _build_driver(viewport_w: int, viewport_h: int, timeout_ms: int):
    opts = Options()
    if CHROME_HEADLESS:
        opts.add_argument("--headless=new")
    opts.add_argument("--disable-gpu")
    opts.add_argument("--no-sandbox")
    opts.add_argument("--disable-dev-shm-usage")
    opts.add_argument("--hide-scrollbars")
    opts.add_argument("--disable-extensions")
    opts.add_argument("--disable-background-networking")
    opts.add_argument("--disable-sync")
    opts.add_argument("--metrics-recording-only")
    opts.add_argument("--mute-audio")
    opts.add_argument("--no-first-run")
    opts.add_argument("--disable-default-apps")
    opts.add_argument("--disable-popup-blocking")
    opts.add_argument("--disable-notifications")
    opts.add_argument("--window-size=%d,%d" % (viewport_w, viewport_h))
    opts.add_argument("--user-agent=Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome Safari/537.36")
    if CHROME_BINARY:
        opts.binary_location = CHROME_BINARY

    service = ChromeService(executable_path=CHROMEDRIVER_PATH) if CHROMEDRIVER_PATH else ChromeService()
    driver = webdriver.Chrome(service=service, options=opts)
    driver.set_page_load_timeout(max(1, timeout_ms // 1000))
    driver.set_script_timeout(max(1, timeout_ms // 1000))
    return driver


def _wait_for_ready(driver, wait_ms: int):
    end = time.time() + (wait_ms / 1000.0)
    while time.time() < end:
        try:
            rs = driver.execute_script("return document.readyState")
            if rs == "complete":
                break
        except Exception:
            pass
        time.sleep(0.1)


def _capture_png(driver) -> bytes:
    return driver.get_screenshot_as_png()


def _make_thumbnail(img_bytes: bytes, tw: int, th: int, fmt: str, quality: int) -> bytes:
    with Image.open(io.BytesIO(img_bytes)) as im:
        im = im.convert("RGBA") if fmt in ("png", "webp") else im.convert("RGB")
        im.thumbnail((tw, th), Image.Resampling.LANCZOS)
        out = io.BytesIO()
        save_kwargs = {}
        if fmt == "jpeg":
            save_kwargs.update({"format": "JPEG", "quality": quality, "optimize": True, "progressive": True})
        elif fmt == "png":
            save_kwargs.update({"format": "PNG", "optimize": True})
        elif fmt == "webp":
            save_kwargs.update({"format": "WEBP", "quality": quality, "method": 6})
        else:
            raise ValueError("unsupported_format")
        im.save(out, **save_kwargs)
        return out.getvalue()


def _sanitize_int(v, default, min_v, max_v):
    try:
        v = int(v)
    except Exception:
        return default
    return max(min_v, min(max_v, v))


def _sanitize_fmt(v: str) -> str:
    v = (v or THUMB_FORMAT).lower().strip()
    if v in ("jpg", "jpeg"):
        return "jpeg"
    if v in ("png",):
        return "png"
    if v in ("webp",):
        return "webp"
    return THUMB_FORMAT


def _render_and_store(url: str, viewport_w: int, viewport_h: int, timeout_ms: int, wait_ms: int, tw: int, th: int, fmt: str, quality: int):
    if not S3_BUCKET:
        raise RuntimeError("S3_BUCKET not configured")

    key = _stable_key(url, viewport_w, viewport_h, tw, th, fmt)
    head = _s3_head(key)
    if head:
        return key, True

    driver = None
    try:
        driver = _build_driver(viewport_w, viewport_h, timeout_ms)
        driver.get(url)
        _wait_for_ready(driver, wait_ms)
        png = _capture_png(driver)
        thumb = _make_thumbnail(png, tw, th, fmt, quality)
        _s3_put_bytes(key, thumb, _content_type_for(fmt))
        return key, False
    finally:
        if driver is not None:
            try:
                driver.quit()
            except Exception:
                pass


@app.get("/health")
def health():
    return jsonify({"ok": True, "time": _now_iso(), "app": APP_NAME})


@app.post("/screenshot")
def screenshot():
    req = request.get_json(silent=True) or {}
    url = req.get("url") or request.args.get("url") or ""
    ok, err = validate_url(url)
    if not ok:
        return jsonify({"ok": False, "error": err}), 400

    viewport_w = _sanitize_int(req.get("viewport_w") or request.args.get("viewport_w"), DEFAULT_VIEWPORT_W, 320, 2560)
    viewport_h = _sanitize_int(req.get("viewport_h") or request.args.get("viewport_h"), DEFAULT_VIEWPORT_H, 240, 2560)
    timeout_ms = _sanitize_int(req.get("timeout_ms") or request.args.get("timeout_ms"), DEFAULT_TIMEOUT_MS, 3000, 60000)
    wait_ms = _sanitize_int(req.get("wait_ms") or request.args.get("wait_ms"), DEFAULT_WAIT_MS, 0, 15000)

    tw = _sanitize_int(req.get("thumb_w") or request.args.get("thumb_w"), THUMB_W, 64, 2000)
    th = _sanitize_int(req.get("thumb_h") or request.args.get("thumb_h"), THUMB_H, 64, 2000)
    fmt = _sanitize_fmt(req.get("format") or request.args.get("format"))
    quality = _sanitize_int(req.get("quality") or request.args.get("quality"), THUMB_QUALITY, 30, 95)

    presign_expires = _sanitize_int(req.get("presign_expires") or request.args.get("presign_expires"), 3600, 60, 7 * 24 * 3600)
    return_image = (req.get("return_image") or request.args.get("return_image") or "0") in ("1", "true", "True")

    with _sema:
        try:
            key, cached = _render_and_store(url, viewport_w, viewport_h, timeout_ms, wait_ms, tw, th, fmt, quality)
        except TimeoutException:
            return jsonify({"ok": False, "error": "timeout"}), 504
        except WebDriverException as e:
            log.exception("webdriver_error")
            return jsonify({"ok": False, "error": "render_failed", "detail": str(e)[:500]}), 502
        except Exception as e:
            log.exception("internal_error")
            return jsonify({"ok": False, "error": "internal_error", "detail": str(e)[:500]}), 500

    if return_image:
        obj = _s3.get_object(Bucket=S3_BUCKET, Key=key)
        data = obj["Body"].read()
        return send_file(io.BytesIO(data), mimetype=_content_type_for(fmt), as_attachment=False, download_name=f"thumb.{fmt}")

    url_signed = _s3_presigned_get(key, expires=presign_expires)
    return jsonify(
        {
            "ok": True,
            "cached": cached,
            "s3_bucket": S3_BUCKET,
            "s3_key": key,
            "url": url_signed,
            "format": fmt,
            "thumb_w": tw,
            "thumb_h": th,
            "time": _now_iso(),
        }
    )


@app.post("/invalidate")
def invalidate():
    req = request.get_json(silent=True) or {}
    url = req.get("url") or ""
    ok, err = validate_url(url)
    if not ok:
        return jsonify({"ok": False, "error": err}), 400

    viewport_w = _sanitize_int(req.get("viewport_w"), DEFAULT_VIEWPORT_W, 320, 2560)
    viewport_h = _sanitize_int(req.get("viewport_h"), DEFAULT_VIEWPORT_H, 240, 2560)
    tw = _sanitize_int(req.get("thumb_w"), THUMB_W, 64, 2000)
    th = _sanitize_int(req.get("thumb_h"), THUMB_H, 64, 2000)
    fmt = _sanitize_fmt(req.get("format"))

    key = _stable_key(url, viewport_w, viewport_h, tw, th, fmt)
    try:
        _s3.delete_object(Bucket=S3_BUCKET, Key=key)
    except Exception as e:
        return jsonify({"ok": False, "error": "delete_failed", "detail": str(e)[:500]}), 500
    return jsonify({"ok": True, "deleted": True, "s3_key": key, "time": _now_iso()})


